#include <bits/stdc++.h>
using namespace std;
struct Edge{
    int to,val;
};
int n,m,c[102],u[102],d[102];
vector<Edge> g[102];
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&c[i],&u[i]);
    for(int i=1;i<=m;i++){
        int x,y,z;
        scanf("%d%d%d",&x,&y,&z);
        g[x].push_back({y,z});
        d[y]++;
    }
    queue<int> s,t;
    for(int i=1;i<=n;i++)
        if(!d[i] && c[i]>0)
            t.push(i);
    while(t.size()){
        s.push(t.front()),t.pop();
        int x=s.back(),len=g[x].size();
        for(int i=0;i<len;i++){
            c[g[x][i].to]+=g[x][i].val*c[x];
            if(!--d[g[x][i].to]){
                c[g[x][i].to]-=u[g[x][i].to];
                if(c[g[x][i].to]>0)
                    t.push(g[x][i].to);
            }
        }
    }
    bool flag=true;
    for(int i=1;i<=n;i++)
        if(c[i]>0 && g[i].size()==0){
            flag=false;
            printf("%d %d\n",i,c[i]);
        }
    if(flag)
        printf("NULL");
    return 0;
}
